using ChurnPredictor;
using Microsoft.Extensions.ML;

var builder = WebApplication.CreateBuilder(args);

var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "ChurnModel.zip");

// Train the model at startup if it doesn't exist yet
if (!File.Exists(modelPath))
{
    ChurnModelTrainer.Train(dataPath, modelPath);
}

// Thread-safe prediction engine for ASP.NET Core
builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API — POST /predict with { age, income, region, purchaseHistory }");

app.MapPost("/predict", (ChurnRequest req, PredictionEnginePool<CustomerData, ChurnPrediction> pool) =>
{
    var input = new CustomerData
    {
        Age = req.Age,
        Income = req.Income,
        Region = req.Region,
        PurchaseHistory = req.PurchaseHistory,
    };

    var prediction = pool.Predict(input);

    return Results.Ok(new
    {
        WillChurn = prediction.Churned,
        Probability = prediction.Probability,
    });
});

app.MapPost("/retrain", () =>
{
    var report = ChurnModelTrainer.Train(dataPath, modelPath);
    return Results.Ok(new { Message = "Model retrained", Report = report });
});

app.Run();

